  ('guitar_amp', 'Quilter', 'SuperBlock US', 'SuperBlock', false, '25 watt SuperBlock US pedalboard head with American voicing.'),
  ('guitar_amp', 'Quilter', 'SuperBlock UK', 'SuperBlock', false, '25 watt SuperBlock UK pedalboard head with British voicing.'),
  ('guitar_amp', 'Quilter', 'OverDrive 202', 'OverDrive', false, '200 watt OverDrive 202 head with dual channels.'),
  ('guitar_amp', 'Quilter', 'Aviator Cub', 'Aviator', false, '50 watt Aviator Cub 1x12 combo.'),
  ('guitar_amp', 'Quilter', '101 Reverb Head', '101', false, '50 watt 101 Reverb pedalboard head.'),
