  ('guitar_amp', 'Hotone', 'Nano Legacy Purple Wind', 'Nano Legacy', false, '5 watt Nano Legacy Purple Wind mini head with high gain voicing.'),
  ('guitar_amp', 'Hotone', 'Nano Legacy Mojo Diamond', 'Nano Legacy', false, '5 watt Nano Legacy Mojo Diamond mini head.'),
